7	export type ModuleFormat = (typeof moduleFormats)[number]
8	
9	export function parseModuleFormat(format: string): ModuleFormat {
10	  switch (format.toLowerCase()) {
11	    case 'cjs':
12	    case 'commonjs':
13	      return 'cjs'
14	    case 'esm':
15	      return 'esm'
16	    default:
17	      throw new Error(`Invalid module format: "${format}", expected "esm" or "cjs"`)
18	  }
19	}
20	
21	export function parseModuleFormatFromUnknown(value: unknown): ModuleFormat {
22	  if (typeof value === 'string') {
23	    return parseModuleFormat(value)
24	  } else {
25	    throw new Error(`Invalid module format: ${JSON.stringify(value)}, expected "esm" or "cjs"`)
26	  }
27	}
28	
29	type InferModuleFormatOptions = {
30	  tsconfig: TsConfigJsonResolved | undefined
31	  generatedFileExtension: GeneratedFileExtension
32	  importFileExtension: GeneratedFileExtension
33	}
34	
35	export function inferModuleFormat({
36	  tsconfig,
37	  generatedFileExtension,
38	  importFileExtension,
39	}: InferModuleFormatOptions): ModuleFormat {
40	  if (tsconfig?.compilerOptions?.module) {
41	    return fromTsConfigModule(tsconfig.compilerOptions.module)
42	  }
43	
44	  if (generatedFileExtension === 'cts' || importFileExtension === 'cjs') {
45	    return 'cjs'
46	  }
47	
48	  return 'esm'
49	}
50	
51	function fromTsConfigModule(module: TsConfigJson.CompilerOptions.Module) {
52	  const normalizedModule = module.toLowerCase() as TsConfigJson.CompilerOptions.Module
53	
54	  if (normalizedModule === 'commonjs') {
55	    return 'cjs'
56	  }
57	
58	  return 'esm'
59	}
