### Step 7: `packages/generator-rest-client/src/template.ts` -- String Template Helpers

Utility functions used by the generator:

```typescript
import type * as DMMF from '@prisma/dmmf'

/**
 * Maps Prisma scalar types to TypeScript types suitable for REST/JSON transport.
 */
const SCALAR_TYPE_MAP: Record<string, string> = {
  String: 'string',
  Int: 'number',
  Float: 'number',
  Boolean: 'boolean',
  Long: 'number',
  DateTime: 'string',
  ID: 'string',
  UUID: 'string',
  Json: 'any',
  Bytes: 'string',
  Decimal: 'string',
  BigInt: 'string',
}

/**
 * Convert a DMMF field to its TypeScript type string.
 * Returns null for object/unsupported fields (relations).
 */
export function fieldToTsType(field: DMMF.Field): string | null {
  let baseType: string

  switch (field.kind) {
    case 'scalar':
      baseType = SCALAR_TYPE_MAP[field.type] ?? 'unknown'
      break
    case 'enum':
      baseType = field.type  // refers to the generated enum type alias
      break
    case 'object':
    case 'unsupported':
      return null  // skip relations and unsupported
    default:
      return null
  }

  if (field.isList) {
    baseType = `${baseType}[]`
  }

  if (!field.isRequired) {
    baseType = `${baseType} | null`
  }

  return baseType
}

/**
 * Indent each line of a string by the given number of spaces.
 */
export function indent(text: string, spaces: number = 2): string {
  const pad = ' '.repeat(spaces)
  return text
    .split('\n')
    .map((line) => (line.trim() ? pad + line : line))
    .join('\n')
}

/**
 * Convert PascalCase to kebab-case for REST URL segments.
 */
export function toKebabCase(str: string): string {
  return str
    .replace(/([a-z0-9])([A-Z])/g, '$1-$2')
    .replace(/([A-Z])([A-Z][a-z])/g, '$1-$2')
    .toLowerCase()
}

/**
 * Lowercase the first character of a string (PascalCase -> camelCase).
 */
export function toLowerFirst(str: string): string {
  return str.charAt(0).toLowerCase() + str.slice(1)
}
```

