import type * as DMMF from '@prisma/dmmf'

/**
 * Maps Prisma scalar types to TypeScript types suitable for JSON/REST transport.
 *
 * Unlike the full Prisma Client type mapping (which uses `Date | string` for DateTime,
 * `bigint | number` for BigInt, etc.), this mapping uses types that survive JSON
 * round-tripping without special serialization.
 */
const SCALAR_TYPE_MAP: Record<string, string> = {
  String: 'string',
  Int: 'number',
  Float: 'number',
  Boolean: 'boolean',
  Long: 'number',
  DateTime: 'string',
  ID: 'string',
  UUID: 'string',
  Json: 'any',
  Bytes: 'string',
  Decimal: 'string',
  BigInt: 'string',
}

/**
 * Convert a DMMF field to its TypeScript type string.
 * Returns `null` for relation (`object`) and `unsupported` fields.
 */
export function fieldToTsType(field: DMMF.Field): string | null {
  let baseType: string

  switch (field.kind) {
    case 'scalar':
      baseType = SCALAR_TYPE_MAP[field.type] ?? 'unknown'
      break
    case 'enum':
      baseType = field.type
      break
    case 'object':
    case 'unsupported':
      return null
    default:
      return null
  }

  if (field.isList) {
    baseType = `${baseType}[]`
  }

  if (!field.isRequired) {
    baseType = `${baseType} | null`
  }

  return baseType
}

/** Indent each line of a string by the given number of spaces. */
export function indent(text: string, spaces: number = 2): string {
  const pad = ' '.repeat(spaces)
  return text
    .split('\n')
    .map((line) => (line.trim() ? pad + line : line))
    .join('\n')
}

/** Convert PascalCase to kebab-case for REST URL path segments. */
export function toKebabCase(str: string): string {
  return str
    .replace(/([a-z0-9])([A-Z])/g, '$1-$2')
    .replace(/([A-Z])([A-Z][a-z])/g, '$1-$2')
    .toLowerCase()
}

/** Lowercase the first character of a string. */
export function toLowerFirst(str: string): string {
  return str.charAt(0).toLowerCase() + str.slice(1)
}

