import type * as DMMF from '@prisma/dmmf'

import { fieldToTsType, indent, toKebabCase, toLowerFirst } from './template'

/** Generate the complete REST client TypeScript source from a DMMF document. */
export function generateRestClient(dmmf: DMMF.Document): string {
  const parts: string[] = []

  parts.push(generatePreamble())

  for (const enumDef of dmmf.datamodel.enums) {
    parts.push(generateEnum(enumDef))
  }

  const modelNames: string[] = []
  for (const model of dmmf.datamodel.models) {
    modelNames.push(model.name)
    parts.push(generateModelInterface(model))
    parts.push(generateCreateInput(model))
    parts.push(generateUpdateInput(model))
    parts.push(generateModelClient(model))
  }

  parts.push(generatePrismaRestClient(modelNames))

  return parts.join('\n\n') + '\n'
}

function generatePreamble(): string {
  return [
    '// This file was auto-generated by @prisma/generator-rest-client.',
    '// Do not edit manually.',
    '/* eslint-disable */',
  ].join('\n')
}

function generateEnum(enumDef: DMMF.DatamodelEnum): string {
  const values = enumDef.values.map((v) => `'${v.name}'`).join(' | ')
  return `export type ${enumDef.name} = ${values}`
}

function generateModelInterface(model: DMMF.Model): string {
  const fields = scalarFields(model).map((field) => {
    const tsType = fieldToTsType(field)!
    return `  ${field.name}: ${tsType}`
  })

  return `export interface ${model.name} {\n${fields.join('\n')}\n}`
}

function generateCreateInput(model: DMMF.Model): string {
  const fields = scalarFields(model)
    .filter((f) => !f.isGenerated && !f.isUpdatedAt)
    .map((field) => {
      const tsType = fieldToTsType(field)!
      const isOptional = field.hasDefaultValue || field.isId || !field.isRequired
      const optionalMark = isOptional ? '?' : ''
      const nullUnion = !field.isRequired ? ' | null' : ''

      if (isOptional && field.isRequired) {
        return `  ${field.name}${optionalMark}: ${tsType}`
      }
      if (isOptional && !field.isRequired) {
        return `  ${field.name}${optionalMark}: ${tsType}`
      }
      return `  ${field.name}: ${tsType}${nullUnion}`
    })

  return `export interface ${model.name}CreateInput {\n${fields.join('\n')}\n}`
}

function generateUpdateInput(model: DMMF.Model): string {
  const fields = scalarFields(model)
    .filter((f) => !f.isId && !f.isReadOnly)
    .map((field) => {
      const tsType = fieldToTsType(field)!
      const nullSuffix = !field.isRequired ? '' : ''
      return `  ${field.name}?: ${tsType}${nullSuffix}`
    })

  return `export interface ${model.name}UpdateInput {\n${fields.join('\n')}\n}`
}

function generateModelClient(model: DMMF.Model): string {
  const idField = findIdField(model)
  const idType = idField ? fieldToTsType({ ...idField, isRequired: true, isList: false }) ?? 'string' : 'string'
  const pathSegment = toKebabCase(model.name)
  const name = model.name

  const methods = [
    generateFindMany(name, pathSegment),
    generateFindUnique(name, pathSegment, idType),
    generateCreate(name, pathSegment),
    generateUpdate(name, pathSegment, idType),
    generateDelete(name, pathSegment, idType),
  ]

  return [
    `export class ${name}Client {`,
    `  #baseUrl: string`,
    '',
    `  constructor(baseUrl: string) {`,
    `    this.#baseUrl = baseUrl`,
    `  }`,
    '',
    methods.map((m) => indent(m)).join('\n\n'),
    `}`,
  ].join('\n')
}

function generateFindMany(name: string, path: string): string {
  return [
    `async findMany(): Promise<${name}[]> {`,
    `  const response = await fetch(\`\${this.#baseUrl}/${path}\`)`,
    `  return response.json() as Promise<${name}[]>`,
    `}`,
  ].join('\n')
}

function generateFindUnique(name: string, path: string, idType: string): string {
  return [
    `async findUnique(id: ${idType}): Promise<${name} | null> {`,
    `  const response = await fetch(\`\${this.#baseUrl}/${path}/\${id}\`)`,
    `  if (response.status === 404) return null`,
    `  return response.json() as Promise<${name}>`,
    `}`,
  ].join('\n')
}

function generateCreate(name: string, path: string): string {
  return [
    `async create(data: ${name}CreateInput): Promise<${name}> {`,
    `  const response = await fetch(\`\${this.#baseUrl}/${path}\`, {`,
    `    method: 'POST',`,
    `    headers: { 'Content-Type': 'application/json' },`,
    `    body: JSON.stringify(data),`,
    `  })`,
    `  return response.json() as Promise<${name}>`,
    `}`,
  ].join('\n')
}

function generateUpdate(name: string, path: string, idType: string): string {
  return [
    `async update(id: ${idType}, data: ${name}UpdateInput): Promise<${name}> {`,
    `  const response = await fetch(\`\${this.#baseUrl}/${path}/\${id}\`, {`,
    `    method: 'PATCH',`,
    `    headers: { 'Content-Type': 'application/json' },`,
    `    body: JSON.stringify(data),`,
    `  })`,
    `  return response.json() as Promise<${name}>`,
    `}`,
  ].join('\n')
}

function generateDelete(name: string, path: string, idType: string): string {
  return [
    `async delete(id: ${idType}): Promise<${name}> {`,
    `  const response = await fetch(\`\${this.#baseUrl}/${path}/\${id}\`, {`,
    `    method: 'DELETE',`,
    `  })`,
    `  return response.json() as Promise<${name}>`,
    `}`,
  ].join('\n')
}

function generatePrismaRestClient(modelNames: string[]): string {
  const properties = modelNames.map((name) => `  ${toLowerFirst(name)}: ${name}Client`).join('\n')

  const assignments = modelNames.map((name) => `    this.${toLowerFirst(name)} = new ${name}Client(baseUrl)`).join('\n')

  return [
    `export class PrismaRestClient {`,
    properties,
    '',
    `  constructor(baseUrl: string) {`,
    assignments,
    `  }`,
    `}`,
  ].join('\n')
}

function scalarFields(model: DMMF.Model): DMMF.Field[] {
  return model.fields.filter((f) => f.kind === 'scalar' || f.kind === 'enum') as DMMF.Field[]
}

function findIdField(model: DMMF.Model): DMMF.Field | undefined {
  const idField = model.fields.find((f) => f.isId)
  if (idField) return idField as DMMF.Field

  // Composite primary key — use the first field
  if (model.primaryKey && model.primaryKey.fields.length > 0) {
    const firstName = model.primaryKey.fields[0]
    return model.fields.find((f) => f.name === firstName) as DMMF.Field | undefined
  }

  return undefined
}

