import type * as DMMF from '@prisma/dmmf'
import { describe, expect, it } from 'vitest'

import { generateRestClient } from '../generator'
import { fieldToTsType, toKebabCase, toLowerFirst } from '../template'

function makeField(overrides: Partial<DMMF.Field>): DMMF.Field {
  return {
    kind: 'scalar',
    name: 'field',
    type: 'String',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    ...overrides,
  } as DMMF.Field
}

describe('template helpers', () => {
  describe('fieldToTsType', () => {
    it('maps String to string', () => {
      expect(fieldToTsType(makeField({ type: 'String' }))).toBe('string')
    })

    it('maps Int to number', () => {
      expect(fieldToTsType(makeField({ type: 'Int' }))).toBe('number')
    })

    it('maps Float to number', () => {
      expect(fieldToTsType(makeField({ type: 'Float' }))).toBe('number')
    })

    it('maps Boolean to boolean', () => {
      expect(fieldToTsType(makeField({ type: 'Boolean' }))).toBe('boolean')
    })

    it('maps DateTime to string for REST transport', () => {
      expect(fieldToTsType(makeField({ type: 'DateTime' }))).toBe('string')
    })

    it('maps BigInt to string for safe JSON serialization', () => {
      expect(fieldToTsType(makeField({ type: 'BigInt' }))).toBe('string')
    })

    it('maps Decimal to string for precision safety', () => {
      expect(fieldToTsType(makeField({ type: 'Decimal' }))).toBe('string')
    })

    it('maps Json to any', () => {
      expect(fieldToTsType(makeField({ type: 'Json' }))).toBe('any')
    })

    it('maps Bytes to string', () => {
      expect(fieldToTsType(makeField({ type: 'Bytes' }))).toBe('string')
    })

    it('returns null for object fields (relations)', () => {
      expect(fieldToTsType(makeField({ kind: 'object', type: 'Post' }))).toBeNull()
    })

    it('returns null for unsupported fields', () => {
      expect(fieldToTsType(makeField({ kind: 'unsupported', type: 'citext' }))).toBeNull()
    })

    it('wraps list fields in array', () => {
      expect(fieldToTsType(makeField({ type: 'String', isList: true }))).toBe('string[]')
    })

    it('adds null union for optional fields', () => {
      expect(fieldToTsType(makeField({ type: 'String', isRequired: false }))).toBe('string | null')
    })

    it('handles list + optional together', () => {
      expect(fieldToTsType(makeField({ type: 'Int', isList: true, isRequired: false }))).toBe('number[] | null')
