describe('generateRestClient', () => {
  const output = generateRestClient(testDmmf)

  it('generates preamble comment', () => {
    expect(output).toContain('// This file was auto-generated by @prisma/generator-rest-client.')
    expect(output).toContain('/* eslint-disable */')
  })

  it('generates enum type aliases', () => {
    expect(output).toContain("export type Role = 'ADMIN' | 'USER'")
  })

  it('generates model interfaces with correct types', () => {
    expect(output).toContain('export interface User {')
    expect(output).toContain('  id: number')
    expect(output).toContain('  email: string')
    expect(output).toContain('  name: string | null')
    expect(output).toContain('  role: Role')
    expect(output).toContain('  createdAt: string')
  })

  it('excludes relation fields from interfaces', () => {
    expect(output).not.toMatch(/posts:.*Post/)
    expect(output).not.toMatch(/author:.*User/)
  })

  it('generates create input with correct optionality', () => {
    expect(output).toContain('export interface UserCreateInput {')
    // id has default (autoincrement) -> optional
    expect(output).toMatch(/id\?: number/)
    // email is required, no default -> required
    expect(output).toMatch(/email: string\n/)
    // name is not required -> optional
    expect(output).toMatch(/name\?: string \| null/)
    // role has default -> optional
    expect(output).toMatch(/role\?: Role/)
    // createdAt has default -> optional
    expect(output).toMatch(/createdAt\?: string/)
  })

  it('excludes isUpdatedAt fields from create input', () => {
    expect(output).not.toMatch(/UserCreateInput[\s\S]*?updatedAt/)
  })

  it('generates update input with all fields optional', () => {
    expect(output).toContain('export interface UserUpdateInput {')
    expect(output).toMatch(/UserUpdateInput \{[\s\S]*?email\?: string/)
    expect(output).toMatch(/UserUpdateInput \{[\s\S]*?name\?: string \| null/)
  })

  it('excludes id and readOnly fields from update input', () => {
    // authorId is readOnly, should not be in PostUpdateInput
    const postUpdateSection = output.slice(output.indexOf('export interface PostUpdateInput {'))
    const postUpdateBlock = postUpdateSection.slice(0, postUpdateSection.indexOf('}') + 1)
    expect(postUpdateBlock).not.toContain('authorId')

    // id should not be in any UpdateInput
    const userUpdateSection = output.slice(output.indexOf('export interface UserUpdateInput {'))
    const userUpdateBlock = userUpdateSection.slice(0, userUpdateSection.indexOf('}') + 1)
    expect(userUpdateBlock).not.toMatch(/\bid\b/)
  })

  it('generates CRUD client classes', () => {
    expect(output).toContain('export class UserClient {')
    expect(output).toContain('async findMany(): Promise<User[]>')
    expect(output).toContain('async findUnique(id: number): Promise<User | null>')
    expect(output).toContain('async create(data: UserCreateInput): Promise<User>')
    expect(output).toContain('async update(id: number, data: UserUpdateInput): Promise<User>')
    expect(output).toContain('async delete(id: number): Promise<User>')
  })

  it('generates PostClient with string id type', () => {
    expect(output).toContain('export class PostClient {')
    expect(output).toContain('async findUnique(id: string): Promise<Post | null>')
    expect(output).toContain('async update(id: string, data: PostUpdateInput): Promise<Post>')
    expect(output).toContain('async delete(id: string): Promise<Post>')
  })

  it('uses kebab-case URL paths', () => {
    expect(output).toContain('`${this.#baseUrl}/user`')
    expect(output).toContain('`${this.#baseUrl}/post`')
  })

  it('generates top-level PrismaRestClient', () => {
    expect(output).toContain('export class PrismaRestClient {')
    expect(output).toContain('user: UserClient')
    expect(output).toContain('post: PostClient')
    expect(output).toContain('this.user = new UserClient(baseUrl)')
    expect(output).toContain('this.post = new PostClient(baseUrl)')
  })

  it('uses correct HTTP methods', () => {
    expect(output).toContain("method: 'POST'")
    expect(output).toContain("method: 'PATCH'")
    expect(output).toContain("method: 'DELETE'")
  })

  it('uses private fields for baseUrl', () => {
    expect(output).toContain('#baseUrl: string')
  })

  it('matches snapshot', () => {
    expect(output).toMatchSnapshot()
  })
})
